import Ticket from "./Ticket";
import Swal from "@supportpal/sweetalert2";
import ZipFile from "./utils/Zip";

export const MessageType = {
    MESSAGES: 'messages',
    NOTES: 'notes',
    ALL: 'all',
} as const;

export type MessageType = typeof MessageType[keyof typeof MessageType];

export default class TicketView
{
    ticket: Ticket;
    ticketId: string;
    notesPosition: number;
    replyOrder: string;
    printing: boolean = false;

    constructor(ticket: Ticket, ticketId: string, notesPosition: number, replyOrder: string = 'ASC') {
        this.ticket = ticket;
        this.ticketId = ticketId;
        this.notesPosition = notesPosition;
        this.replyOrder = replyOrder;

        this.registerListeners();
    }

    load(onLoadComplete?: () => void): void {
        // Load messages sequentially to avoid race conditions
        let loadPromise: JQuery.Promise<any>;

        // If ticketId is not provided, skip loading messages (for print views that don't need dynamic loading)
        if (! this.ticketId) {
            loadPromise = $.Deferred().resolve().promise();
        } else if (this.notesPosition === 0) {
            loadPromise = this.loadInitialMessages(MessageType.NOTES).then(() => {
                return this.loadInitialMessages(MessageType.ALL);
            });
        } else if (this.notesPosition === 1) {
            loadPromise = this.loadInitialMessages(MessageType.NOTES).then(() => {
                return this.loadInitialMessages(MessageType.MESSAGES);
            });
        } else {
            loadPromise = this.loadInitialMessages(MessageType.ALL);
        }

        const instance = this;
        loadPromise.always(function() {
            instance.scrollToLinkedMessage();

            // Show 'expand all' button if any message is collapsed.
            if ($('.sp-message-collapsed').length) {
                $('.expand-messages').show();
            }

            instance.ticket.viewingTicket(instance.ticketId);

            // Call the callback if provided
            if (onLoadComplete) {
                onLoadComplete();
            }
        });
    }

    setPrinting(printing: boolean): void {
        this.printing = printing;
    }

    /**
     * Load initial messages (optimized: up to MESSAGE_LOAD_LIMIT recent unread messages with full text + oldest excerpt).
     */
    loadInitialMessages(type: MessageType): JQuery.Promise<any> {
        const params: any = {
            ticket_id: this.ticketId,
            type: type,
            print: this.printing
        };

        let $container = this.getContainer(type);

        return $.get(this.ticket.getMessageIndexRoute(params))
            .done((response) => {
                if (response.status === 'success' && response.data) {
                    this.renderInitialMessages($container, response.data, type);
                    this.updateAvatarVisibility($container);
                }
            })
            .fail((xhr) => {
                this.handleLoadError(xhr);
            })
            .always(() => {
                $container.find('.sp-loading').remove();
            });
    }

    /**
     * Load more messages in batch (collapsed state).
     */
    loadMoreMessages(
        type: MessageType,
        $button: JQuery<HTMLElement>
    ): JQuery.Promise<any> {
        const params = this.buildLoadMoreParams(type, $button);

        return $.get(this.ticket.getMessageIndexRoute(params))
            .done((response) => {
                if (response.status === 'success' && response.data) {
                    this.handleLoadMoreSuccess(response.data, $button, type);
                }
            })
            .fail((xhr) => {
                this.handleLoadMoreError(xhr, $button);
            });
    }

    /**
     * Load a specific message with context window (2 before + 2 after).
     */
    loadMessageWithContext(id: string, type: MessageType): JQuery.Promise<any> {
        const params: any = {
            ticket_id: this.ticketId,
            type: type,
            id: id,
            print: this.printing
        };

        const $container = this.getContainer(type);

        // Show loading placeholder
        const $placeholder = this.createLoadingPlaceholder();
        $placeholder.insertBefore($container);

        return $.get(this.ticket.getMessageIndexRoute(params))
            .done((response) => {
                if (response.status === 'success' && response.data && response.data.is_context_load) {
                    this.renderContextMessages($container, response.data, type);
                    this.updateAvatarVisibility($container);
                }
            })
            .fail((xhr) => {
                this.handleLoadError(xhr);
            })
            .always(() => {
                // Remove loading placeholder
                $placeholder.remove();
            });
    }

    print() {
        var $a = $('.sp-print-ticket a');
        if ($a.length === 0) {
            return;
        }

        window.open($a.attr('href'), '_blank');
    }

    expand ($message: JQuery<HTMLElement>) {
        // AJAX load the message into the view.
        this.ticket.loadMessage($message);
        this.ticket.showMessage($message);
    }

    static collapse ($message: JQuery<HTMLElement>) {
        // If we're collapsing and the edit view is showing, hide it and show the normal message view.
        if ($message.hasClass('sp-message-collapsible') && $message.find('.sp-message-text-edit').is(':visible')) {
            $message.find('.sp-message-text').show();
            $message.find('.sp-message-text-edit').hide();
        }

        // Toggle between collapsed and collapsible mode
        $message.find('.sp-message-text').children('.sp-message-text-original').addClass('sp:hidden');
        $message.find('.sp-message-text').children('.sp-message-text-trimmed').removeClass('sp:hidden');
        $message.addClass('sp-message-collapsed');
        $message.removeClass('sp-message-collapsible');
    }

    /**
     * Recursively load all collapsed message sections until there are no more to load.
     * Loads sequentially to avoid race conditions in message counting.
     * Returns a promise that resolves when all messages are loaded.
     */
    loadAllCollapsedSections (): JQuery.Promise<any> {
        const instance = this;
        const $button = $('.sp-collapsed-messages').first();

        // If there's a collapsed section to load
        if ($button.length > 0) {
            // Show loading state
            instance.showLoadingState($button);

            // Load this section, then recursively check for more
            return instance.loadMoreMessages($button.data('type'), $button).then(function () {
                // Check if there are still more collapsed sections after loading
                if ($('.sp-collapsed-messages').length > 0) {
                    return instance.loadAllCollapsedSections(); // Recursive call
                }

                return $.Deferred().resolve().promise();
            });
        }

        // No more buttons to load
        return $.Deferred().resolve().promise();
    }

    expandAll () {
        const instance = this;

        // Load all messages first, then expand them
        this.loadAllCollapsedSections().always(function () {
            // Now expand all collapsed messages
            $('.sp-messages-container .sp-message-collapsed').each(function () {
                instance.expand($(this));
            });

            $('.collapse-messages').show();
            $('.expand-messages').hide();
        });
    }

    collapseAll () {
        $('.sp-messages-container .sp-message-collapsible').each(function () {
            TicketView.collapse($(this));
        });

        $('.collapse-messages').hide();
        $('.expand-messages').show();
    }

    /**
     * Check if we should show entries on the timeline of a certain type.
     */
    showOnTimeline(type: string): boolean {
        const $input = $('.sp-filter-timeline').find('input[type="checkbox"][name="' + type + '"]');

        if ($input.length === 0) {
            return true; // Default to enabled if no filter found
        }

        return $input.prop('checked');
    }

    /**
     * Scroll to a specific message by ID or jQuery element.
     * If message is not in DOM, load it with context first.
     *
     * @param idOrElement allows either a string ID (e.g., "notes-123") or a jQuery element.
     */
    scrollToMessage(idOrElement: string | JQuery<HTMLElement>): void {
        const instance = this;

        if (typeof idOrElement === 'string') {
            // Split type and ID
            const id = parseInt(idOrElement.split('-').pop() || '0');

            // This expects ID to be a timeline entry. In BC cases, like note-123, or message-123, it will return
            // false and we will ajax load the context. This should only occur on page load (link to a specific message).
            let $message = this.ticket.getMessageFromTimelineId(id);

            if ($message === false) {
                // Determine type.
                const type = idOrElement.startsWith('note-') ? MessageType.NOTES : MessageType.ALL;

                // Message not in DOM yet, need to load it with context
                Swal.showLoading();
                this.loadMessageWithContext(idOrElement, type).done(function(response) {
                    if (response.status === 'success' && response.data && response.data.target_timeline_id) {
                        // Construct the hash with the new timeline ID, preserving the type prefix (note- or message-)
                        const prefix = idOrElement.split('-')[0];
                        const newHash = prefix + '-' + response.data.target_timeline_id;

                        // Try to get the message again after loading
                        const $loadedMessage = instance.ticket.getMessageFromHash(newHash);
                        if ($loadedMessage !== false) {
                            instance.performScrollToMessage($loadedMessage as JQuery<HTMLElement>);
                        }
                    }
                }).always(function() {
                    Swal.close();
                });
            } else {
                // Message is in DOM, scroll to it
                const messageElement = $message as JQuery<HTMLElement>;
                instance.performScrollToMessage(messageElement);
            }
        } else {
            // It's already a jQuery element
            this.performScrollToMessage(idOrElement);
        }
    }

    /**
     * Insert a new message into the DOM (e.g., after submitting a reply or note).
     * Handles notes positioning and sorted insertion.
     *
     * @param html The HTML string of the message to insert.
     * @returns The inserted jQuery element(s).
     */
    insertMessage(html: string): JQuery<HTMLElement> {
        let $message = $(html);
        const isNote = $message.hasClass('sp-note');

        // It's a note and we need to show it somewhere else than messages block only.
        if (isNote && (this.notesPosition === 0 || this.notesPosition === 1)) {
            // Show the notes area (in case its first note)
            $('.notes-header, .sp-messages-container[data-position="top"]').removeClass('sp:hidden');

            // Add to notes area
            const $notesContainer = this.ticket.getMessagesContainer().filter('[data-position="top"]');
            this.insertMessageIntoContainer($notesContainer, $message);

            // Add to message area if notesPosition === 0
            if (this.notesPosition === 0) {
                const $inlineContainer = this.ticket.getMessagesContainer().filter('[data-position="inline"]');
                const $clone = $message.clone();
                this.insertMessageIntoContainer($inlineContainer, $clone);
                $message = $message.add($clone);

                // Update avatar visibility for both containers
                this.updateAvatarVisibility($notesContainer);
                this.updateAvatarVisibility($inlineContainer);
            } else {
                // Update avatar visibility for notes container only
                this.updateAvatarVisibility($notesContainer);
            }
        } else {
            // We need to just show it in the messages block
            const $inlineContainer = this.ticket.getMessagesContainer().filter('[data-position="inline"]');
            this.insertMessageIntoContainer($inlineContainer, $message);

            // Update avatar visibility for inline container
            this.updateAvatarVisibility($inlineContainer);
        }

        return $message;
    }

    private scrollToLinkedMessage(): void {
        const hash = window.location.hash.substring(1);
        if (! hash) {
            return;
        }

        this.scrollToMessage(hash);
    }

    private filterTimelineShowCheckAll($inputGroup: JQuery<HTMLElement>): void {
        const $checkboxes = $inputGroup.find('li:not(.sp\\:hidden) input[type="checkbox"]');
        const allChecked = $checkboxes.length > 0 && $checkboxes.filter(':checked').length === $checkboxes.length;

        $inputGroup.find('.check_all').toggle(! allChecked);
        $inputGroup.find('.uncheck_all').toggle(allChecked);
    }

    private registerListeners() {
        const instance = this;

        // Filter timeline
        $('.sp-filter-timeline').on('change', 'input[type="checkbox"]', function (e) {
            instance.filterTimeline(
                instance.ticket.getMessagesContainer().last(),
                $(this).attr('name') || '',
                $(this).prop('checked')
            );

            // Show check or uncheck all link
            instance.filterTimelineShowCheckAll($(this).closest('.sp-input-group'));

            // Save the filtering preferences
            const formData: { [key: string]: string } = {};
            $('.sp-filter-timeline input[type="checkbox"]').each(function() {
                const name = $(this).attr('name');
                if (name && $(this).prop('checked')) {
                    formData[name] = '1';
                }
            });

            $.post(laroute.route('ticket.operator.ticket.updateTimelineFiltering'), formData);
        });

        // Show check or uncheck all link for each filter timeline group.
        $('.sp-filter-timeline .sp-input-group').each(function () {
            instance.filterTimelineShowCheckAll($(this));
        });

        // Handle check_all/uncheck_all buttons locally to prevent dropdown from closing
        $('.sp-filter-timeline').on('click', '.check_all, .uncheck_all', function (e) {
            e.preventDefault();
            e.stopPropagation();

            const checked = $(this).hasClass('check_all');
            $(this).closest('.sp-input-group')
                .find('input[type="checkbox"]')
                .prop('checked', checked)
                .trigger('change');
        });

        // Prevent dropdown action clicks from closing the dropdown.
        $('.sp-filter-timeline.sp-dropdown-container').on('click', '.sp-dropdown li', function (e) {
            e.stopPropagation();
        });

        // Collapsing or opening message
        $(document).on('click', '.sp-message-collapsed .sp-message-header-interactive, .sp-message-collapsible .sp-message-header .sp-message-header-interactive', function (e) {
            e.stopPropagation();
        });

        $(document).on('click', '.sp-message-collapsed', function () {
            instance.expand($(this));
        });
        $(document).on('click', '.sp-message-collapsible .sp-message-header', function () {
            TicketView.collapse($(this).parents('.sp-message-collapsible'));
        });

        // Expand/collapse all messages on click
        $('.expand-messages').on('click', instance.expandAll.bind(instance));
        $('.collapse-messages').on('click', instance.collapseAll.bind(instance));

        const $container = this.ticket.getMessagesContainer();

        $container.on('click', '.sp-download-all', function () {
            var $attachments = $(this).parents('ul.sp-attachments').find('li[data-filename]');
            var filename = instance.ticket.getSubject();

            (new ZipFile).create($attachments, filename)
        });

        $container
            // Expand quoted areas
            .on('click', '.expandable', function () {
                $(this).next().toggle();
            })
            // Open links in a new window/tab. Needs rel="noopener" due to
            // https://www.jitbit.com/alexblog/256-targetblank---the-most-underestimated-vulnerability-ever/
            .on('click', '.sp-message .sp-message-text a', function () {
                $(this).attr('target', '_blank').attr('rel', 'noopener');
            })
            .on('click', 'a[href^="#"]', function (event) {
                event.preventDefault();

                var hash = $(this).attr('href').substring(1);
                if (hash !== null) {
                    instance.scrollToMessage(hash);
                }
            });
    }

    /**
     * Render initial messages in the container.
     */
    private renderInitialMessages($container: JQuery<HTMLElement>, data: any, type: "messages" | "notes" | "all"): void {
        if (!data.messages || data.messages.length === 0) {
            return;
        }

        // If it's the notes section, ensure it's visible as we otherwise hide it.
        if ($container.data('position') === 'top') {
            $container.removeClass('sp:hidden')
                .prev('.sp-container-header').removeClass('sp:hidden');
        }

        const {newestMessages, oldestMessage} = this.separateInitialMessages(data.messages);

        if (this.replyOrder === 'DESC') {
            // Descending: [newest] [button] [oldest]
            this.insertMessages($container, newestMessages);
            this.renderLoadMoreButton($container, data.hidden_count, type, data.initial_cursor);
            this.renderOldestMessage($container, oldestMessage, type);
        } else {
            // Ascending: [oldest] [button] [newest]
            this.renderOldestMessage($container, oldestMessage, type);
            this.renderLoadMoreButton($container, data.hidden_count, type, data.initial_cursor);
            this.insertMessages($container, newestMessages);
        }
    }

    /**
     * Separate initial messages into newest and oldest groups.
     * Backend now returns up to MESSAGE_LOAD_LIMIT recent messages (prioritizing unread) plus the oldest.
     */
    private separateInitialMessages(messages: any[]): {newestMessages: any[], oldestMessage: any[]} {
        if (messages.length === 0) {
            return {newestMessages: [], oldestMessage: []};
        }

        const sortedMessages = this.sortMessagesByCreatedAtAndId(messages);

        // If only one message, treat it as newest
        if (sortedMessages.length === 1) {
            return {newestMessages: sortedMessages, oldestMessage: []};
        }

        // The oldest message is the last one (with lowest created_at/ID)
        const oldestMessage = [sortedMessages[sortedMessages.length - 1]];

        // All others are "newest" messages (recent messages, prioritizing unread)
        const newestMessages = sortedMessages.slice(0, -1);

        return {newestMessages, oldestMessage};
    }

    /**
     * Render the load more button if there are hidden messages.
     */
    private renderLoadMoreButton($container: JQuery<HTMLElement>, hiddenCount: number, type: "messages" | "notes" | "all", initialCursor?: string): void {
        if (hiddenCount > 0) {
            this.addLoadMoreButton($container, hiddenCount, type, initialCursor);
        }
    }

    /**
     * Render the oldest message.
     */
    private renderOldestMessage($container: JQuery<HTMLElement>, oldestMessage: any[], type: string): void {
        if (oldestMessage.length > 0) {
            // Append oldest message directly to end, don't use ordered insertion
            oldestMessage.forEach((message) => {
                const $newMessage = $(message.view);
                const timelineId = parseInt($newMessage.attr('data-timeline-id') || '0');

                // Check for duplicates
                if (timelineId > 0 && $container.find(`[data-timeline-id="${timelineId}"]`).length > 0) {
                    return;
                }

                // Only show if timeline filtering allows (for inline messages)
                if ($container.attr('data-position') === 'inline'
                    && ! this.showOnTimeline($newMessage.attr('data-type') || 'message')
                ) {
                    $newMessage.addClass('sp:hidden');
                }

                $container.append($newMessage);

                this.ticket.initMessage($newMessage);

                this.triggerInsertedEvent($newMessage);
            });
        }
    }

    /**
     * Handle load error.
     */
    private handleLoadError(xhr: any): void {
        console.error('Failed to load messages:', xhr);
        Swal.fire(Lang.get('messages.error'), Lang.get('messages.error_loading_message'), 'error');
    }

    /**
     * Build parameters for loading more messages.
     */
    private buildLoadMoreParams(type: string, $button: JQuery<HTMLElement>): any {
        const countAttr = $button.attr('data-count');
        const count = parseInt(countAttr || '0', 10) || 0;
        const limit = count > 10 ? null : count;

        const params: any = {
            ticket_id: this.ticketId,
            type: type,
            print: this.printing
        };

        if (limit) {
            params.limit = limit;
        }

        const cursor = $button.attr('data-next-cursor');
        if (cursor) {
            params.cursor = cursor;
        }

        return params;
    }

    /**
     * Handle successful load more response.
     */
    private handleLoadMoreSuccess(data: any, $button: JQuery<HTMLElement>, type: MessageType): void {
        const $container = this.getContainer(type);
        const isContextButton = $button.attr('data-context-position');

        $button.remove();

        if (!data.data || data.data.length === 0) {
            return;
        }

        let insertedMessages: JQuery<HTMLElement>[] = this.insertMessages($container, data.data);

        this.setupUnreadMessagesLazyLoad(insertedMessages);

        if (data.next_page_url) {
            if (isContextButton) {
                // Calculate position after insertion - button goes after the last inserted message
                const lastInsertedMessage = insertedMessages[insertedMessages.length - 1];
                const newButtonPosition = lastInsertedMessage.index();
                this.addContextLoadMoreButtonAtPosition(data, $container, type, newButtonPosition, isContextButton);
            } else {
                this.addLoadMoreButtonIfNeeded(data, $container, type);
            }
        }

        // Update avatar visibility after all messages have been inserted
        this.updateAvatarVisibility($container);
    }

    /**
     * Insert messages into the container in the correct order.
     */
    private insertMessages($container: JQuery<HTMLElement>, messages: any[]): JQuery<HTMLElement>[] {
        const insertedMessages: JQuery<HTMLElement>[] = [];
        messages.forEach((message: any) => {
            const $newMessage = this.insertMessageIntoContainer($container, message);
            insertedMessages.push($newMessage);
        });

        return insertedMessages;
    }

    /**
     * Add context load more button at specific position.
     */
    private addContextLoadMoreButtonAtPosition(
        data: any,
        $container: JQuery<HTMLElement>,
        type: MessageType,
        position: number,
        contextPosition: string
    ): void {
        const remainingCount = this.calculateRemainingCount(data, $container);

        if (remainingCount > 0) {
            const $newButton = this.createLoadMoreButton(remainingCount, data.next_cursor, type, contextPosition);

            // Insert at the specified position
            const $children = $container.children();
            if (position >= $children.length) {
                $container.append($newButton);
            } else {
                $children.eq(position).before($newButton);
            }
        }
    }

    /**
     * Set up lazy loading for unread messages.
     */
    private setupUnreadMessagesLazyLoad(messages: JQuery<HTMLElement>[]): void {
        const instance = this;
        messages.forEach($msg => {
            if ($msg.hasClass('sp-message-collapsible')) {
                instance.setupLazyLoadForUnreadMessage($msg);
            }
        });
    }

    /**
     * Add load more button if there are remaining messages.
     */
    private addLoadMoreButtonIfNeeded(data: any, $container: JQuery<HTMLElement>, type: "messages" | "notes" | "all"): void {
        const remainingCount = this.calculateRemainingCount(data, $container);

        if (this.shouldShowLoadMoreButton(remainingCount, $container)) {
            this.createNewLoadMoreButton(remainingCount, data.next_cursor, $container, type);
        }
    }

    /**
     * Calculate remaining message count.
     */
    private calculateRemainingCount(data: any, $container: JQuery<HTMLElement>): number {
        const $allMessages = $container.children('.sp-message').not('.sp-collapsed-messages');
        const loadedCount = $allMessages.length;
        const totalCount = data.total_count;
        const collapsedCount = $container.find('.sp-collapsed-messages')
            .map((i, e) => $(e).data('count') || 0)
            .get()
            .reduce((total, count) => total + count, 0);

        return totalCount - loadedCount - collapsedCount;
    }

    /**
     * Check if load more button should be shown.
     */
    private shouldShowLoadMoreButton(remainingCount: number, $container: JQuery<HTMLElement>): boolean {
        const $oldestInContainer = $container.children('.sp-message').not('.sp-collapsed-messages').last();
        return remainingCount > 0 && $oldestInContainer.length > 0;
    }

    /**
     * Create a new load more button.
     */
    private createNewLoadMoreButton(
        count: number,
        nextCursor: string,
        $container: JQuery<HTMLElement>,
        type: "messages" | "notes" | "all"
    ): void {
        const $newButton = this.createLoadMoreButton(count, nextCursor, type);

        let $message = $container.children('.sp-message').not('.sp-collapsed-messages');
        if (this.replyOrder === 'DESC') {
          $message.last().before($newButton);
        } else {
          $message.first().after($newButton);
        }
    }

    /**
     * Create a load more button element with event handler.
     */
    private createLoadMoreButton(
        count: number,
        nextCursor: string | undefined,
        type: MessageType,
        contextPosition?: string
    ): JQuery<HTMLElement> {
        const label = Lang.get('ticket.older_messages', {count: count});
        const $button = $('<div class="sp-collapsed-messages"><span>' + label + '</span></div>');
        $button.attr('data-count', count);
        $button.attr('data-type', type);

        // Store the next cursor on the button for next load
        if (nextCursor) {
            $button.attr('data-next-cursor', nextCursor);
        }

        // Store context position if provided
        if (contextPosition) {
            $button.attr('data-context-position', contextPosition);
        }

        // Attach click handler
        const instance = this;
        $button.on('click', function() {
            instance.showLoadingState($(this));
            instance.loadMoreMessages(type, $(this));
        });

        return $button;
    }

    /**
     * Handle load more error.
     */
    private handleLoadMoreError(xhr: any, $button: JQuery<HTMLElement>): void {
        console.error('Failed to load more messages:', xhr);
        $button.removeClass('sp-loading')
            .find('span').html(Lang.get('ticket.older_messages', {count: ''}));
        Swal.fire(Lang.get('messages.error'), Lang.get('messages.error_loading_message'), 'error');
    }

    /**
     * Get the container for a specific message type.
     */
    private getContainer(type: MessageType): JQuery<HTMLElement> {
        let $container = this.ticket.getMessagesContainer();

        if (type === MessageType.NOTES) {
            $container = $container.filter('[data-position="top"]');
        } else {
            $container = $container.filter('[data-position="inline"]');
        }

        return $container;
    }

    /**
     * Insert a single message in the correct position.
     *
     * @param $container The container to insert into.
     * @param message Either a message object with a .view property, or a jQuery element.
     */
    private insertMessageIntoContainer($container: JQuery<HTMLElement>, message: any): JQuery<HTMLElement> {
        const $newMessage: JQuery<HTMLElement> = message.view !== undefined ? $(message.view) : message;
        const newTimelineId = parseInt($newMessage.attr('data-timeline-id') || '0');

        if (newTimelineId === 0) {
            this.insertMessageFallback($container, $newMessage);
            return $newMessage;
        }

        if (this.messageExists($container, newTimelineId)) {
            return $newMessage;
        }

        // Only show if timeline filtering allows (for inline messages)
        if ($container.attr('data-position') === 'inline'
            && ! this.showOnTimeline($newMessage.attr('data-type') || 'message')
        ) {
            $newMessage.addClass('sp:hidden');
        }

        this.insertMessageInOrder($container, $newMessage, newTimelineId);

        this.ticket.initMessage($newMessage);

        this.triggerInsertedEvent($newMessage);

        return $newMessage;
    }

    /**
     * Fallback insertion for messages without ID.
     */
    private insertMessageFallback($container: JQuery<HTMLElement>, $message: JQuery<HTMLElement>): void {
        if (this.replyOrder === 'DESC') {
            $container.append($message);
        } else {
            $container.prepend($message);
        }
    }

    /**
     * Trigger event after message insertion.
     */
    private triggerInsertedEvent($message: JQuery<HTMLElement>): void {
        $(document).trigger('sp.ticket.message.inserted', [$message]);
    }

    /**
     * Check if message already exists in container.
     */
    private messageExists($container: JQuery<HTMLElement>, timelineId: number): boolean {
        return $container.find(`[data-timeline-id="${timelineId}"]`).length > 0;
    }

    /**
     * Insert message in the correct order based on created_at timestamp and then timeline ID.
     */
    private insertMessageInOrder(
        $container: JQuery<HTMLElement>,
        $message: JQuery<HTMLElement>,
        timelineId: number
    ): void {
        const createdAt = parseInt($message.attr('data-created-at') || '0');
        const insertionPoint = this.findInsertionPoint($container, timelineId, createdAt);

        if (insertionPoint) {
            $message.insertBefore(insertionPoint);
        } else {
            $container.append($message);
        }
    }

    /**
     * Find the correct insertion point for a message.
     */
    private findInsertionPoint($container: JQuery<HTMLElement>, timelineId: number, createdAt: number): JQuery<HTMLElement> | null {
        let insertionPoint: JQuery<HTMLElement> | null = null;

        $container.children('.sp-message')
            .not('.sp-collapsed-messages')
            .each((index, element) => {
              const $existing = $(element);
              const existingTimelineId = parseInt($existing.attr('data-timeline-id') || '0');
              const existingCreatedAt = parseInt($existing.attr('data-created-at') || '0');

              if (existingTimelineId === 0) {
                  return; // continue
              }

              if (this.shouldInsertBefore(timelineId, createdAt, existingTimelineId, existingCreatedAt)) {
                  insertionPoint = $existing;
                  return false; // break
              }
          });

        return insertionPoint;
    }

    /**
     * Determine if message should be inserted before existing message.
     * Orders by created_at first, then by ID (same logic as MessageLoader).
     */
    private shouldInsertBefore(
        newTimelineId: number,
        newCreatedAt: number,
        existingTimelineId: number,
        existingCreatedAt: number
    ): boolean {
        if (this.replyOrder === 'DESC') {
            // Descending: newer messages first (created_at DESC, id DESC)
            if (newCreatedAt !== existingCreatedAt) {
                return newCreatedAt > existingCreatedAt;
            }

            return newTimelineId > existingTimelineId;
        } else {
            // Ascending: older messages first (created_at ASC, id ASC)
            if (newCreatedAt !== existingCreatedAt) {
                return newCreatedAt < existingCreatedAt;
            }

            return newTimelineId < existingTimelineId;
        }
    }

    /**
     * Sort messages by created_at first, then by id (DESC - newest first).
     * Matches MessageLoader backend logic: orderBy('created_at', 'desc')->orderByRaw('id DESC')
     */
    private sortMessagesByCreatedAtAndId(messages: any[]): any[] {
        return messages.sort((a: any, b: any) => {
            // Compare created_at first
            if (b.created_at !== a.created_at) {
                return b.created_at - a.created_at;
            }

            // If created_at is the same, compare by id
            return b.id - a.id;
        });
    }

    /**
     * Add a "load more" button to load additional messages.
     */
    private addLoadMoreButton(
        $container: JQuery<HTMLElement>,
        count: number,
        type: MessageType,
        cursor?: string,
        position?: string
    ): void {
        const $button = this.createLoadMoreButton(count, cursor, type, position);
        this.appendLoadMoreButton($container, $button);
    }

    /**
     * Show loading state on button.
     */
    private showLoadingState($button: JQuery<HTMLElement>): void {
        $button.addClass('sp-loading')
            .find('span').html('<i class="fa-solid fa-spinner fa-pulse"></i> ' + Lang.get('general.loading') + '...');
    }

    /**
     * Append load more button to container.
     */
    private appendLoadMoreButton($container: JQuery<HTMLElement>, $button: JQuery<HTMLElement>): void {
        $container.append($button);
    }

    /**
     * Set up Intersection Observer to lazy load full text for unread messages when they scroll into view.
     */
    private setupLazyLoadForUnreadMessage($message: JQuery<HTMLElement>): void {
        if (!this.isIntersectionObserverSupported()) {
            this.loadMessageImmediately($message);
            return;
        }

        const observer = this.createIntersectionObserver($message);
        this.observeMessage(observer, $message);
    }

    /**
     * Check if IntersectionObserver is supported.
     */
    private isIntersectionObserverSupported(): boolean {
        return 'IntersectionObserver' in window;
    }

    /**
     * Load message immediately (fallback for unsupported browsers).
     */
    private loadMessageImmediately($message: JQuery<HTMLElement>): void {
        this.ticket.loadMessage($message);
    }

    /**
     * Create an IntersectionObserver for lazy loading.
     */
    private createIntersectionObserver($message: JQuery<HTMLElement>): IntersectionObserver {
        const instance = this;

        return new IntersectionObserver((entries, observer) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    instance.handleMessageIntersection($message, observer, entry.target);
                }
            });
        }, this.getIntersectionObserverOptions());
    }

    /**
     * Get IntersectionObserver options.
     */
    private getIntersectionObserverOptions(): IntersectionObserverInit {
        return {
            rootMargin: '200px',
            threshold: 0.01
        };
    }

    /**
     * Handle message intersection (load and expand message).
     */
    private handleMessageIntersection(
        $message: JQuery<HTMLElement>,
        observer: IntersectionObserver,
        target: Element
    ): void {
        this.ticket.loadMessage($message, () => {
            this.ticket.showMessage($message);
        });

        observer.unobserve(target);
    }

    /**
     * Start observing a message element.
     */
    private observeMessage(observer: IntersectionObserver, $message: JQuery<HTMLElement>): void {
        const messageElement = $message[0];
        if (messageElement) {
            observer.observe(messageElement);
        }
    }

    /**
     * Render messages loaded with context window.
     */
    private renderContextMessages($container: JQuery<HTMLElement>, data: any, type: MessageType): void {
        if (!data.messages || data.messages.length === 0) {
            return;
        }

        // Clear the container first - context loading replaces initial load
        $container.empty();

        // If it's the notes section, ensure it's visible as we otherwise hide it.
        if ($container.data('position') === 'top') {
            $container.removeClass('sp:hidden')
                .prev('.sp-container-header').removeClass('sp:hidden');
        }

        // Separate messages into groups: newest, context window, oldest
        const {newestMessages, contextMessages, oldestMessage, targetMessage} =
            this.separateContextMessages(data.messages, data.target_timeline_id);

        if (this.replyOrder === 'DESC') {
            // Descending: [newest] [button?] [context] [button?] [oldest]
            this.insertMessages($container, newestMessages);

            if (data.hidden_before_target > 0) {
                this.addLoadMoreButton(
                    $container,
                    data.hidden_before_target,
                    type,
                    data.cursor_before_target,
                    'before_target',
                );
            }

            this.insertMessages($container, contextMessages);

            if (data.hidden_after_target > 0) {
                this.addLoadMoreButton(
                    $container,
                    data.hidden_after_target,
                    type,
                    data.cursor_after_target,
                    'after_target',
                );
            }

            this.renderOldestMessage($container, oldestMessage, type);
        } else {
            // Ascending: [oldest] [button?] [context] [button?] [newest]
            this.renderOldestMessage($container, oldestMessage, type);

            if (data.hidden_after_target > 0) {
                this.addLoadMoreButton(
                    $container,
                    data.hidden_after_target,
                    type,
                    data.cursor_after_target,
                    'after_target',
                );
            }

            this.insertMessages($container, contextMessages);

            if (data.hidden_before_target > 0) {
                this.addLoadMoreButton(
                    $container,
                    data.hidden_before_target,
                    type,
                    data.cursor_before_target,
                    'before_target',
                );
            }

            this.insertMessages($container, newestMessages);
        }
    }

    /**
     * Separate context messages into groups.
     */
    private separateContextMessages(messages: any[], targetTimelineId: number): {
        newestMessages: any[],
        contextMessages: any[],
        oldestMessage: any[],
        targetMessage: any
    } {
        const sortedMessages = this.sortMessagesByCreatedAtAndId(messages);

        // Find target message
        const targetMessage = sortedMessages.find((m: any) => m.id === targetTimelineId);

        // Newest messages are before context window (first 2)
        const newestMessages: any[] = [];
        const contextMessages: any[] = [];
        const oldestMessage: any[] = [];

        const lastIndex = sortedMessages.length - 1;

        sortedMessages.forEach((msg: any, index: number) => {
            if (index < 2) {
                // First 2 messages go to newestMessages
                newestMessages.push(msg);
            } else if (index === lastIndex) {
                // Last message always goes to oldestMessage
                oldestMessage.push(msg);
            } else {
                // Everything else goes to contextMessages
                contextMessages.push(msg);
            }
        });

        return {newestMessages, contextMessages, oldestMessage, targetMessage};
    }

    /**
     * Create a loading placeholder element.
     */
    private createLoadingPlaceholder(): JQuery<HTMLElement> {
        return $('<div class="sp-loading sp:p-3 sp:mx-6 sp:bg-secondary sp:rounded sp:text-center">' +
            '<i class="fa-solid fa-spinner fa-pulse"></i> ' +
            Lang.get('general.loading') + '...' +
            '</div>');
    }

    /**
     * Filter timeline by type (e.g. show/hide log messages).
     */
    private filterTimeline($container: JQuery<HTMLElement>, type: string, show: boolean = false): void {
        $container.find('.sp-message[data-type=' + type + ']').toggleClass('sp:hidden', ! show);

        this.updateAvatarVisibility($container);
    }

    /**
     * Perform the actual scroll to message operation.
     */
    private performScrollToMessage($message: JQuery<HTMLElement>): void {
        // AJAX load the message into the view.
        this.ticket.loadMessage($message);

        // Toggle collapsed state.
        if ($message.hasClass('sp-message-collapsed')) {
            $message.toggleClass('sp-message-collapsible sp-message-collapsed')
                .find('.sp-message-text')
                .children('.sp-message-text-original, .sp-message-text-trimmed').toggle();
        }

        // Special effects, set as blue for 3 seconds.
        $message.addClass('sp-new-message');
        setTimeout(function () {
            $message.removeClass('sp-new-message');
        }, 3000);

        // Scroll to it.
        $message[0].scrollIntoView({behavior: 'smooth'});
    }

    /**
     * Update avatar visibility for all messages in the container.
     * Delegates to the ticket instance's implementation.
     */
    private updateAvatarVisibility($container: JQuery<HTMLElement>): void {
        this.ticket.updateAvatarVisibility($container);
    }
}
