/**
 * Reply form header controls (sticky, minimise, maximise, resize)
 */
export default class ReplyFormControls {
    private isResizing: boolean = false;
    private form: JQuery<HTMLElement> | null = null;
    private startY: number = 0;
    private startHeight: number = 0;
    private minHeight: number = 320;
    private defaultMaxHeight: string = 'calc(100vh - 6rem)';
    private storageKey: string = 'sp-reply-form-height';
    private stickyStorageKey: string = 'sp-reply-form-sticky';
    private replyOrder: string;

    constructor(replyOrder: string) {
        this.replyOrder = replyOrder;
        this.init();
    }

    private init(): void {
        this.initForm();
        this.attachEventListeners();
    }

    private initForm(): void {
        this.form = $('.ticket-reply-form');

        const storedHeight = this.getStoredHeight();
        const isSticky = this.getStoredIsSticky();

        // Handle if not sticky.
        if (!isSticky) {
            this.toggleSticky();

            // Don't set the height again below.
            return;
        }

        // Restore stored height if available.
        if (storedHeight && storedHeight >= this.minHeight) {
            this.setHeight(storedHeight);
        }
    }

    private attachEventListeners(): void {
        // Button clicks.
        $(document)
            .on('click', '.sp-reply-form-sticky', (e) => {
                e.preventDefault();
                this.toggleSticky(true);
            })
            .on('click', '.sp-reply-form-minimise', (e) => {
                e.preventDefault();
                this.minimiseForm();
            })
            .on('click', '.sp-reply-form-maximise', (e) => {
                e.preventDefault();
                this.expandForm($(e.currentTarget));
            })
            .on('click', '.sp-reply-form-resize', (e) => {
                e.preventDefault();
                this.compressForm($(e.currentTarget));
            });

        // Resize handle.
        $(document).on('mousedown', '.sp-reply-form-resize-handle', (e) => {
            e.preventDefault();
            e.stopPropagation();
            this.startResize(e);
        });

        // Resize mouse handlers.
        $(document)
            .on('mousemove.replyFormResize', (e) => this.handleMouseMove(e))
            .on('mouseup.replyFormResize', () => this.stopResize())
            .on('mouseleave.replyFormResize', () => {
                if (this.isResizing) {
                    this.stopResize();
                }
            })
            .on('keydown.replyFormResize', (e) => {
                if (e.key === 'Escape' && this.isResizing) {
                    this.stopResize();
                }
            })
            .on('contextmenu.replyFormResize', () => {
                if (this.isResizing) {
                    this.stopResize();
                }
            });

        $(window)
            .on('mouseup.replyFormResize', () => this.stopResize())
            .on('blur.replyFormResize', () => {
                if (this.isResizing) {
                    this.stopResize();
                }
            });

        $(document).on('visibilitychange.replyFormResize', () => {
            if (document.hidden && this.isResizing) {
                this.stopResize();
            }
        });
    }

    private toggleSticky(update: boolean = false): void {
        const maxAllowedHeight = this.getMaxAllowedHeight();
        if (maxAllowedHeight) {
            this.defaultMaxHeight = maxAllowedHeight + 'px';
        }

        if (!this.form) {
            return;
        }

        this.form.toggleClass('sp:sticky sp:z-50');
        this.form.find('.sp-reply-form-header').toggleClass('sp:sticky sp:top-0 sp:z-10002', this.form.hasClass('sp:sticky'));
        this.form.find('.sp-reply-form-resize-handle').toggleClass('sp:sm:block', this.form.hasClass('sp:sticky'));
        this.form.find('.sp-reply-form-sticky').toggleClass('sp:hidden');
        this.form.find('.sp-reply-form-maximise').toggleClass('sp:hidden', ! this.form.hasClass('sp:sticky'));
        if (! this.form.hasClass('sp:sticky')) {
            this.form.find('.sp-reply-form-resize').addClass('sp:hidden');
        }

        // Set classes based on position it is now.
        this.form.removeClass('sp:order-first sp:mt-6 sp:mb-6 sp:border-b');
        if (this.form.hasClass('sp:sticky')) {
            this.form.addClass('sp:mt-6');
        } else {
            if (this.replyOrder === 'ASC') {
                this.form.addClass('sp:mt-6');
            } else {
                this.form.addClass('sp:order-first sp:mt-0 sp:mb-6 sp:border-b');
            }

            // Clear height restrictions.
            this.form.css({'height': 'auto', 'max-height': 'none'});
        }

        if (update) {
            // Store sticky state.
            this.setStoredIsSticky(this.form.hasClass('sp:sticky'));

            if (this.form.hasClass('sp:sticky')) {
                // Restore stored height if available and it's sticky.
                const storedHeight = this.getStoredHeight();
                if (storedHeight && storedHeight >= this.minHeight) {
                    this.setHeight(storedHeight);
                }
            } else {
                // scroll to the form if it's not visible
                this.form[0].scrollIntoView({behavior: 'smooth'});
            }
        }
    }

    private minimiseForm(): void {
        if (! this.form) {
            return;
        }

        const formTypes: Record<string, string> = {
            '.message-form': 'toggleReplyForm',
            '.notes-form': 'toggleNotesForm',
            '.forward-form': 'toggleForwardForm'
        };

        for (const [className, methodName] of Object.entries(formTypes)) {
            if (this.form.find(className + ":visible").length) {
                if (typeof App.TicketViewForm !== 'undefined' && typeof App.TicketViewForm[methodName] === 'function') {
                    App.TicketViewForm[methodName]();
                } else {
                    this.form.addClass('sp:hidden');
                }
                break;
            }
        }
    }

    private expandForm($this: JQuery<HTMLElement>): void {
        if (! this.form) {
            return;
        }

        const maxAllowedHeight = this.getMaxAllowedHeight();
        const height = maxAllowedHeight ? (maxAllowedHeight + 'px') : this.defaultMaxHeight;

        this.form.css({
            'height': height,
            'max-height': height
        });

        $this.addClass('sp:hidden');
        $('.sp-reply-form-resize').removeClass('sp:hidden');

    }

    private compressForm($this: JQuery<HTMLElement>): void {
        if (! this.form) {
            return;
        }

        const storedHeight = this.getStoredHeight();

        // Restore stored height if available.
        if (storedHeight && storedHeight >= this.minHeight) {
            this.setHeight(storedHeight);
        } else {
            this.form.css({
                'height': '',
                'max-height': ''
            });
        }

        $this.addClass('sp:hidden');
        $('.sp-reply-form-maximise').removeClass('sp:hidden');
    }

    private startResize(e: JQuery.MouseDownEvent): void {
        if (this.isResizing || ! this.form) {
            return;
        }

        this.isResizing = true;
        this.startY = e.pageY;
        this.startHeight = this.form.outerHeight() as number;

        this.form.addClass('sp-resizing');
        $('body').addClass('sp-resize-cursor');
    }

    private handleMouseMove(e: JQuery.MouseMoveEvent): void {
        if (! this.isResizing) {
            return;
        }

        e.preventDefault();

        const deltaY = this.startY - e.pageY;
        let newHeight = Math.max(this.minHeight, this.startHeight + deltaY);

        this.setHeight(newHeight);
    }

    private setHeight(newHeight: number): void {
        if (! this.form) {
            return;
        }

        // Calculate max allowed height.
        const maxAllowedHeight = this.getMaxAllowedHeight();
        if (maxAllowedHeight) {
            // If it's under 640px, they can't resize so it should automatically be capped..
            if (window.innerHeight < 640) {
                newHeight = maxAllowedHeight;
            } else {
                newHeight = Math.min(newHeight, maxAllowedHeight);
            }
        }

        this.form.css({
            'height': newHeight + 'px',
            'max-height': maxAllowedHeight ? (maxAllowedHeight + 'px') : this.defaultMaxHeight
        });

        this.form.find('.sp-reply-form-maximise').toggleClass('sp:hidden', newHeight === maxAllowedHeight);
        this.form.find('.sp-reply-form-resize').toggleClass('sp:hidden', newHeight !== maxAllowedHeight);
    }

    private stopResize(): void {
        if (! this.isResizing) {
            return;
        }

        this.isResizing = false;

        if (this.form) {
            this.setStoredHeight(this.form.outerHeight() as number);
            this.form.removeClass('sp-resizing');
        }

        $('body').removeClass('sp-resize-cursor');
        this.startY = 0;
        this.startHeight = 0;
    }

    private getMaxAllowedHeight(): number | null {
        if (! this.form) {
            return null;
        }

        const $content = this.form.closest('#content');

        if ($content.length) {
            const contentHeight = $content.height() as number;
            const quickActionsHeight = $('.sp-quick-actions').outerHeight() || 0;

            return contentHeight - quickActionsHeight;
        }

        return null;
    }

    private getStoredHeight(): number | null {
        try {
            const stored = localStorage.getItem(this.storageKey);
            return stored ? parseInt(stored, 10) : null;
        } catch (e) {
            return null;
        }
    }

    private setStoredHeight(height: number): void {
        try {
            localStorage.setItem(this.storageKey, height.toString());
        } catch (e) {
            // Silently fail if localStorage is not available.
        }
    }

    private getStoredIsSticky(): boolean {
        try {
            const stored = localStorage.getItem(this.stickyStorageKey);
            return stored === null ? true : stored === 'true'; // Default to sticky (true).
        } catch (e) {
            return true; // Default to sticky.
        }
    }

    private setStoredIsSticky(isSticky: boolean): void {
        try {
            localStorage.setItem(this.stickyStorageKey, isSticky.toString());
        } catch (e) {
            // Silently fail if localStorage is not available.
        }
    }
}

declare const App: any;

