import DraftMessage from "../DraftMessage";
import timeAgo from "../../../libs/timeago"

export default class OperatorDraftMessage extends DraftMessage
{
    private static readonly messageId = 'newMessage';
    private static readonly noteId = 'newNote';
    private static readonly forwardId = 'newForward';
    private replyTemplate: string;

    constructor(replyTemplate: string) {
        super();

        this.replyTemplate = replyTemplate;

        this.registerOtherDraftListeners();
    }


    getTextEditors(): string[] {
        return [
            OperatorDraftMessage.messageId,
            OperatorDraftMessage.noteId,
            OperatorDraftMessage.forwardId,
        ];
    }

    getStoreRoute(): string {
        return laroute.route('ticket.operator.message.store');
    }

    getDiscardRoute(): string {
        return laroute.route('ticket.operator.message.discard');
    }

    getDiscardData($form: JQuery<HTMLElement>): {} {
        const replyType = $form.find('input[name="reply_type"]').val();

        return { ticket_id: $form.data('ticket-id'), reply_type: replyType };
    }

    setMessageDraft(value: string) {
        this.setDraft(OperatorDraftMessage.messageId, value);
    }

    setNoteDraft(value: string) {
        this.setDraft(OperatorDraftMessage.noteId, value);
    }

    setForwardDraft(value: string) {
        this.setDraft(OperatorDraftMessage.forwardId, value);
    }

    saveDraft($form: JQuery<HTMLElement>, useBeacon: boolean): void {
        var editor = $form.find('textarea:not(.CodeMirror textarea)').eq(0).editor(),
            messageWithoutCursorMarker = editor.getContent({withoutCursorMarker: true}),
            message = editor.getContent(),
            type = $form.find('input[name="reply_type"]').val();

        // Update draft message variable
        if (type == '1') {
            this.setNoteDraft(messageWithoutCursorMarker);
        } else if (type == '2') {
            this.setForwardDraft(messageWithoutCursorMarker);
        } else {
            this.setMessageDraft(messageWithoutCursorMarker);
        }

        var $usages = $form.find('input[name="cannedresponse_usage[]"]');
        var data = {
            _token: $('meta[name=csrf_token]').prop('content'),
            ticket: [ $form.data('ticket-id') ],
            reply_type: type,
            is_draft: 1,
            text: message,
            from_address: type == '2' ? $form.find('select[name="from_address"]').val() : null,
            to_address: type == '2' ? $form.find('select[name="to_address[]"]').val() : null,
            cc_address: type == '2' ? $form.find('select[name="cc_address[]"]').val() : null,
            bcc_address: type == '2' ? $form.find('select[name="bcc_address[]"]').val() : null,
            subject: type == '2' ? $form.find('input[name="subject"]').val() : null,
            cannedresponse_usage: $usages.val(),
        };

        // Remove them otherwise their usage will be counted twice (when the message is posted).
        $usages.remove();

        // Add attachments to AJAX data.
        this.addAttachmentsToData($form, data);

        if (useBeacon) {
            this.storeDraftUsingBeacon(data);
        } else {
            this.storeDraftUsingAjax($form, data)
                .then(function () {
                    // Show draft icon in quick action
                    $('.sp-reply-type .sp-action[data-type=' + type + '] .sp-draft-icon').removeClass('sp:hidden');
                });
        }
    }

    discardDraft($form: JQuery<HTMLElement>): IPromise<{}> {
        const instance = this,
            replyType = $form.find('input[name="reply_type"]').val();

        return super.discardDraft($form)
            .then(function (response: {status: 'success'|'error'}) {
                if (response.status == 'success') {
                    // Remove draft icon in quick action
                    $('.sp-reply-type .sp-action[data-type=' + replyType + '] .sp-draft-icon').addClass('sp:hidden');

                    // Clear editor
                    if (replyType == 1) {
                        $('#newNote').editor().setContent('');
                        instance.setNoteDraft($('#newNote').editor().getContent({withoutCursorMarker: true}));
                    } else if (replyType == 2) {
                        $('#newForward').editor().setContent('');
                        instance.setForwardDraft($('#newForward').editor().getContent({withoutCursorMarker: true}));
                    } else {
                        $('#newMessage').editor().setContent(instance.replyTemplate);
                        $('#newMessage').editor().focus();
                        instance.setMessageDraft($('#newMessage').editor().getContent({withoutCursorMarker: true}));
                    }
                }

                return response;
            });
    }

    registerOtherDraftListeners(): void {
        $('.ticket-reply-form')
            // Show a draft message.
            .on('click', '.sp-reply-form-draft', function () {
                const $draftButton = $(this),
                    $previewContainer = $('.sp-draft-preview');

                // Toggle close.
                if ($previewContainer.data('message-id') === $draftButton.data('message-id')
                    && ! $previewContainer.hasClass('sp:hidden')
                ) {
                    $draftButton.removeClass('sp:bg-yellow-800!');
                    $previewContainer.addClass('sp:hidden');

                    return;
                }

                // Set button to active and stop pulsing.
                $draftButton.addClass('sp:bg-yellow-800!')
                    .removeClass('sp:animate-pulse');
                $previewContainer.removeClass('sp:hidden');

                // Show loading state.
                const $loading = $previewContainer.find('.sp-draft-preview-loading');
                $loading.removeClass('sp:hidden');

                // Load draft and show.
                $.get(laroute.route('ticket.operator.message.showJson', {id: $draftButton.data('message-id')}))
                    .done(function (response) {
                        $loading.addClass('sp:hidden');

                        $previewContainer.data('message-id', response.data.id);

                        $previewContainer.find('.sp-draft-preview-title')
                            .html('')
                            .html($draftButton.attr('data-title') || '');

                        if (typeof timeAgo !== 'undefined') {
                            timeAgo.render($('time.timeago'));
                        }

                        $previewContainer.find('.sp-draft-preview-content')
                            .html(response.data.purified_text);
                    })
                    .catch(function (error) {
                        if (error.status === 404 || error.status === 403) {
                            $draftButton.remove();
                        }

                        // Error, reset everything.
                        $draftButton.removeClass('sp:bg-yellow-800!');
                        $previewContainer.addClass('sp:hidden');
                        $loading.removeClass('sp:hidden');
                    });
            });
    }
}
