function truncateMiddle(str: string, max: number) {
  if (str.length <= max) return str;
  const ext = str.lastIndexOf('.') > -1 ? str.slice(str.lastIndexOf('.')) : '';
  const name = str.slice(0, str.lastIndexOf('.') > -1 ? str.lastIndexOf('.') : str.length);
  const available = max - ext.length - 3;
  const frontChars = Math.ceil(available / 2);
  const backChars = Math.floor(available / 2);
  return name.slice(0, frontChars) + '...' + name.slice(-backChars) + ext;
}

export {truncateMiddle};
