import Ticket from "../Ticket";

export default class FrontendTicket extends Ticket
{
    getSubject(): string {
        return $('meta[name="ticket-subject"]').prop('content');
    }

    getMessagesContainer(): JQuery<HTMLElement> {
        return $('.sp-messages-container');
    }

    getMessageFromTimelineId(id: number): JQuery<HTMLElement> | false {
        // Get messages.
        var messages = $('.sp-message[data-timeline-id="' + id + '"]');

        return messages.length >= 1 ? messages.first() : false;
    }

    getMessageFromHash(hash: string): false | JQuery<HTMLElement> {
        // id should be in the format notes-%ID% so we need to split it into those two components.
        var components = hash.split('-');
        if (components.length !== 2 || ! /^\d+$/.test(components[1])) {
            return false;
        }

        return this.getMessageFromTimelineId(parseInt(components[1]));
    }

    getLoadMessageRoute($message: JQuery<HTMLElement>): string {
        let token = $('meta[name="token"]').prop('content'),
            route = laroute.route('ticket.frontend.message.showJson', { id: $message.data('id') });
        if (token.length !== 0) {
            route += "?token=" + token;
        }

        return route;
    }

    getMessageIndexRoute(params: Record<string, any>): string {
      let token = $('meta[name="token"]').prop('content');
      if (token.length !== 0) {
        params.token = token;
      }

      return laroute.route('ticket.frontend.message.index', params);
    }

    viewingTicket(ticketId: string) {
        //
    }
}
