/**
 * Reply options & set status.
 */
export default class ReplyOptions {
    private checkboxes: CheckboxRegistry;
    private closedStatusId: number;
    private departmentTemplates: DepartmentTemplates;

    constructor(closedStatusId: number, departmentTemplates: DepartmentTemplates) {
        this.checkboxes = this.initializeCheckboxes();
        this.closedStatusId = closedStatusId;
        this.departmentTemplates = departmentTemplates;

        this.init();
    }

    private init(): void {
        this.setupCheckboxHandlers();
        this.setupEventListeners();
        this.initializeBackToGrid();
        this.initializeToStatus();
    }

    /**
     * Initialize checkbox registry with jQuery selectors
     */
    private initializeCheckboxes(): CheckboxRegistry {
        return {
            user: {
                checkbox: $('.message-form input[name="send_email_to_users"]') as JQuery<HTMLInputElement>
            },
            operator_reply: {
                checkbox: $('.message-form input[name="send_email_to_operators"]') as JQuery<HTMLInputElement>
            },
            operator_note: {
                checkbox: $('.notes-form  input[name="send_email_to_operators"]') as JQuery<HTMLInputElement>
            }
        };
    }

    /**
     * Setup handlers for checkbox state management
     */
    private setupCheckboxHandlers(): void {
        $.each(this.checkboxes, (_index: string, value: CheckboxConfig) => {
            // Save the state of the checkbox initially and on change
            value.state = value.checkbox.is(':checked');

            value.checkbox.on('change', () => {
                value.state = value.checkbox.is(':checked');
            });

            // If the checkbox is disabled, uncheck it
            if (value.checkbox.prop('disabled')) {
                value.checkbox.prop('checked', false);
            }
        });
    }

    /**
     * Setup event listeners.
     */
    private setupEventListeners(): void {
        // Handle changing status in dropdown.
        $('a.sp-to-status').on('click', (event) => {
            const statusId = $(event.currentTarget).data('id') as number;
            const statusIcon = $(event.currentTarget).find('div.sp\\:rounded-full')[0].outerHTML as string;

            // Update the hidden input and action icon.
            const $container = $(event.currentTarget).parents('.sp-dropdown-container');
            $container.parent().find('input[name="to_status"]').val(statusId);
            $container.find('.sp-action').html(statusIcon);

            // Set selected.
            $container.find('li').removeClass('sp-selected');
            $(event.currentTarget).parent('li').addClass('sp-selected');

            this.changeToStatus(statusId);
        })

        // Handle switching back to grid option
        $('input[type="checkbox"][name="back_to_grid"]').on('change', (event) => {
            const $label = $(event.currentTarget).parents('label'),
                checked = $(event.currentTarget).prop('checked');

            $label.find('.sp-back-to-grid-go')
                .toggleClass('sp:hidden', ! checked);
            $label.find('.sp-back-to-grid-stay')
                .toggleClass('sp:hidden', checked);
        });

        // Prevent dropdown action clicks from closing the dropdown.
        $('.sp-reply-options.sp-dropdown-container').on('click', '.sp-dropdown li', function (e) {
            e.stopPropagation();
        });
    }

    /**
     * Initialize back to grid option.
     */
    private initializeBackToGrid(): void {
        // Mock a change to have it run the event listener.
        $('input[type="checkbox"][name="back_to_grid"]').trigger('change');
    }

    /**
     * Initialize to status and handle checkboxes accordingly.
     */
    private initializeToStatus(): void {
        const currentStatus = $('.message-form input[name="to_status"]').val() as number;
        this.changeToStatus(currentStatus);
    }

    /**
     * Check if send email checkbox should be checked based on department email template
     */
    private handleEmailCheckbox(template: number, name: keyof CheckboxRegistry): void {
        const checkboxConfig = this.checkboxes[name];

        if (template !== -1) {
            checkboxConfig.checkbox
                .prop('disabled', false)
                .prop('checked', checkboxConfig.state ?? false);

            checkboxConfig.checkbox.parent().removeAttr('data-tippy-content');
        } else {
            checkboxConfig.checkbox
                .prop('checked', false)
                .prop('disabled', true);

            checkboxConfig.checkbox.parent().attr(
                'data-tippy-content',
                Lang.get('ticket.department_template_disabled')
            );
        }
    }

    /**
     * Handle status change and update email checkbox accordingly
     */
    private changeToStatus(selected: number): void {
        const userCheckbox: keyof CheckboxRegistry = 'user';

        if (selected === this.closedStatusId && this.departmentTemplates.user_ticket_operatorclose !== -1) {
            // Fall back to normal ticket reply email if operator closed email is disabled
            this.handleEmailCheckbox(this.departmentTemplates.user_ticket_operatorclose, userCheckbox);
        } else {
            this.handleEmailCheckbox(this.departmentTemplates.user_ticket_reply, userCheckbox);
        }
    }
}

interface CheckboxConfig {
    checkbox: JQuery<HTMLInputElement>;
    state?: boolean;
}

interface CheckboxRegistry {
    user: CheckboxConfig;
    operator_reply: CheckboxConfig;
    operator_note: CheckboxConfig;
}

export interface DepartmentTemplates {
    user_ticket_operatorclose: number;
    user_ticket_reply: number;
    operator_operator_ticket_reply: number;
    operator_ticket_note: number;
}

declare const Lang: {
    get: (key: string) => string;
    choice: (key: string, count: number) => string;
};
