import { saveAs } from 'file-saver';
import JSZip from "jszip/dist/jszip";
import JSZipUtils from 'jszip-utils/dist/jszip-utils';
import Swal from "@supportpal/sweetalert2";

interface Attachment {
    filename: string;
    url: string;
}

class ZipFile {
    /**
     * Fetch the content and return the associated promise.
     *
     * @param url the url of the content to fetch.
     * @return the promise containing the data.
     */
    private urlToPromise(url: string): Promise<ArrayBuffer> {
        return new Promise<ArrayBuffer>((resolve, reject) => {
            JSZipUtils.getBinaryContent(url, (err: Error | null, data: ArrayBuffer) => {
                if (err) {
                    reject(err);
                } else {
                    resolve(data);
                }
            });
        });
    }

    private appendToFilename(filename: string, string: string): string {
        const dotIndex = filename.lastIndexOf(".");
        if (dotIndex === -1) {
            return filename + string;
        }

        return filename.substring(0, dotIndex) + string + filename.substring(dotIndex);
    }

    private normalize($attachments: JQuery): Attachment[] {
        const counts: Record<string, number> = {};

        return $attachments.map((index: number, element: HTMLElement): Attachment => {
            const $element = $(element);
            const filename = $element.data('filename') as string;
            counts[filename] = (typeof counts[filename] === "undefined") ? 0 : counts[filename] + 1;

            return {
                filename: this.appendToFilename(filename, (counts[filename] > 0 ? ` (${counts[filename]})` : '')),
                url: $element.data('download-url') as string
            };
        }).get();
    }

    /**
     * Create a zip file from attachments and trigger download.
     *
     * @param $attachments jQuery collection of attachment elements
     * @param filename Name for the zip file (without extension)
     */
    public create($attachments: JQuery, filename: string): void {
        $('.sp-all-attachments.sp-alert').fadeIn();

        if (typeof filename !== 'string') {
            filename = 'attachments';
        } else {
            filename = filename.trim().replace(/[^a-z0-9]/gi, '_').toLowerCase();
            if (filename.length === 0) {
                filename = 'attachments';
            }
        }

        const zip = new JSZip();

        // Get the files we want to include in the zip.
        const attachments = this.normalize($attachments);
        attachments.forEach((attachment) => {
            zip.file(attachment.filename, this.urlToPromise(attachment.url), { binary: true });
        });

        // Download files, build zip, and trigger download of zip.
        zip
            .generateAsync({ type: "blob" })
            .then((blob: Blob) => {
                saveAs(blob, filename + '.zip');

                $('.sp-all-attachments.sp-alert').fadeOut();
            }, (e: Error) => {
                Swal.fire(Lang.get('messages.error'), e.message, 'error');
            });
    }

    static isSupported(): boolean {
        return JSZip.support.blob && typeof window.Promise !== 'undefined';
    }
}

export default ZipFile;
