export default class ViewingTicket {
    private readonly ticketId: string;
    private readonly milliseconds: number;
    private loopTimer: ReturnType<typeof setTimeout> | null = null;
    private xhr: JQuery.jqXHR<any> | null = null;

    constructor(ticketId: string, milliseconds: number) {
        this.ticketId = ticketId;
        this.milliseconds = milliseconds;

        this.registerListener();
    }

    runNow () {
        this.stop();
        console.log('[' + new Date().toUTCString() + '][Viewing Ticket] Sending AJAX');

        return this.xhr = $.ajax({
            url: laroute.route('ticket.operator.ticket.viewing', {'id': this.ticketId}),
            dataType: "json"
        });
    };

    start () {
        const instance = this;
        this.runNow().always(function () {
            instance.loopTimer = setTimeout(() => instance.start(), instance.milliseconds);
        });
    };

    stop () {
        console.log('[' + new Date().toUTCString() + '][Viewing Ticket] Cancelling current running requests.');
        this.loopTimer && clearTimeout(this.loopTimer);
        this.xhr && this.xhr.abort();
    };

    private registerListener() {
        const instance = this;

        // When window is not active, stop polling.
        $(document).on('visibilitychange', function () {
            if (document.hidden) {
                console.log('[' + new Date().toUTCString() + '][Viewing Ticket] Tab is not visible.');
                instance.stop();
            } else {
                console.log('[' + new Date().toUTCString() + '][Viewing Ticket] Tab is visible.');
                instance.start();
            }
        });
    }
}
