import Ticket from "../Ticket";
import ViewingTicket from "./ViewingTicket";
import ReplyFormControls from "./ReplyFormControls";
import ReplyOptions, {DepartmentTemplates} from "./ReplyOptions";

export default class OperatorTicket extends Ticket
{
    private authUserId: string;
    private readonly replyOrder: string;

    constructor(authUserId: string, replyOrder: string, closedStatusId: number, departmentTemplates: DepartmentTemplates) {
      super();

      this.authUserId = authUserId;
      this.replyOrder = replyOrder;

      new ReplyFormControls(replyOrder);
      new ReplyOptions(closedStatusId, departmentTemplates);
    }

    initMessage($message: JQuery<HTMLElement>): void {
        super.initMessage($message);

        // If more than one message, show split ticket button and checkboxes
        if ($('.sp-message').length > 1) {
            $('span.split-ticket').removeClass('sp:hidden');
        }

        // Highlight user mentions.
        const instance = this;
        $message.find('.sp-editor-content .sp-mention:not(.sp-current-user)').each(function () {
            if ($(this).attr('value') === instance.authUserId) {
                $(this).addClass('sp-current-user');
            }
        });
    }

    /**
     * Update avatar visibility for all messages in a container.
     * Hides avatars when consecutive messages are from the same user.
     */
    updateAvatarVisibility($container: JQuery<HTMLElement>): void {
        const $messageSelector = '.sp-message[data-type^="message_"]';
        const $avatarSelector = '.sp-message-avatar img';
        const $messages = $container.find($messageSelector);

        // Reset: show all avatars and headers before recalculating groups.
        $messages.find($avatarSelector).removeClass('sp:hidden');

        // Hide the avatar and header for each message that continues a run
        // of messages from the same user (i.e. the preceding visible message
        // in display order belongs to the same user).
        $messages.each((_index, element) => {
            const $message = $(element);
            const userId = $message.data('user-id');

            if (!userId) {
                return; // continue — no user ID, treat as a group boundary
            }

            // "Next" here means the adjacent message in display order:
            //   ASC (oldest→newest, top→bottom) → the DOM-next sibling
            //   DESC (newest→oldest, top→bottom) → the DOM-prev sibling
            const $adjacentMessage = this.replyOrder === 'ASC'
                ? $message.nextAll($messageSelector).first()
                : $message.prevAll($messageSelector).first();

            if ($adjacentMessage.length && $adjacentMessage.data('user-id') === userId) {
                // $hideMessage is the *later* message in display order —
                // the one that continues the group and should be condensed.
                const $hideMessage = this.replyOrder === 'ASC' ? $adjacentMessage : $message;
                $hideMessage.find($avatarSelector).addClass('sp:hidden');
            }
        });
    }

    getSubject(): string {
        return $('.sp-ticket-subject').text();
    }

    getMessagesContainer(): JQuery<HTMLElement> {
        return $('.sp-messages-container');
    }

    getMessageFromTimelineId(id: number, notesOnly: boolean = false): JQuery<HTMLElement> | false {
        const instance = this;
        var messages = $('.sp-message[data-timeline-id="' + id + '"]').filter(function () {
            var isInline: boolean = instance.getMessagePosition($(this)) === "inline";

            return notesOnly ? ! isInline : isInline;
        });

        return messages.length >= 1 ? messages.first() : false;
    }

    getMessageFromHash(hash: string): JQuery<HTMLElement> | false {
        // id should be in the format notes-%ID% so we need to split it into those two components.
        var components = hash.split('-');
        if (components.length !== 2 || ! /^\d+$/.test(components[1])) {
            return false;
        }

        // Check whether a note (displayed at the top) or a message has been requested.
        var notesOnly = components[0].toUpperCase() === this.getNotesPlaceholder().replace('-%ID%', '').toUpperCase();

        return this.getMessageFromTimelineId(parseInt(components[1]), notesOnly);
    }

    getMessagePosition($message: JQuery<HTMLElement>): "top"|"inline" {
        if ($message.parents("[data-position='top']").length) {
            return "top";
        }

        return "inline";
    }

    getTimelineId($message: JQuery<HTMLElement>): string {
        const match = $message.attr('class')?.match(/sp-timeline-(\d+)/);
        if (match) {
            return match[1];
        }

        throw new Error('Unable to determine timeline ID from message classes.');
    }

    getMessageHash($message: JQuery<HTMLElement>): string {
        // Check if it's in top or inline position.
        if ($message.hasClass('sp-note') && this.getMessagePosition($message) === "top") {
            return this.getNotesPlaceholder().replace('%ID%', $message.data('id'))
        } else {
            return this.getTimelinePlaceholder().replace('%ID%', $message.data('timeline-id'));
        }
    }

    getNotesPlaceholder(): string {
        return $('meta[name="notes-url-id"]').prop('content');
    }

    getTimelinePlaceholder(): string {
        return $('meta[name="timeline-url-id"]').prop('content');
    }

    getLoadMessageRoute($message: JQuery<HTMLElement>): string {
        return laroute.route('ticket.operator.message.showJson', {id: $message.data('id')});
    }

    getMessageIndexRoute(params: Replacements[]): string {
      return laroute.route('ticket.operator.message.index', params);
    }

    viewingTicket(ticketId: string) {
        const viewing = new ViewingTicket(ticketId, 60000);
        viewing.start();
    }
}
