import Swal from "@supportpal/sweetalert2";
import {truncateMiddle} from "./utils/Str";
import ZipFile from "./utils/Zip";
import timeAgo from "../../libs/timeago/index";

export default abstract class Ticket {
    private messageDfd;
    private messageDfdNext;

    constructor() {
        this.messageDfd = $.Deferred();
        this.messageDfdNext = this.messageDfd;
        this.messageDfd.resolve()
    }

    abstract getMessagesContainer(): JQuery<HTMLElement>;
    abstract getMessageFromTimelineId(id: number): JQuery<HTMLElement>|false;
    abstract getMessageFromHash(hash: string): JQuery<HTMLElement>|false;
    abstract getLoadMessageRoute($message: JQuery<HTMLElement>): string;
    abstract getMessageIndexRoute(params: Replacements[]): string;
    abstract getSubject(): string;
    abstract viewingTicket(ticketId: string): void;

    print(): void {
        const instance = this;

        // Lock the interface and show a waiting spinner (this may take a while on a large ticket).
        Swal.fire({
            title: Lang.get('general.loading'),
            allowOutsideClick: false,
            didOpen: () => {
                Swal.showLoading();

                var deferred: JQuery.Promise<any>[] = [];
                $('.sp-message').each((index, message) => {
                    const $message = $(message);
                    deferred.push(instance.loadMessage($message, () => instance.showMessage($message)));
                });

                $.when.apply($, deferred).then(() => Swal.close());
            },
            didClose: function () {
                setTimeout(window.print, 100);
            }
        });
    }

    loadMessage($message: JQuery, successCallback: Function|null = null): any {
        const instance = this;

        // This holds the trimmed and original versions of the message.
        var $text = $message.find('.sp-message-text');
        if ($text.length === 0) {
            return $.Deferred().resolve();
        }

        // If we're not currently in the processing of loading the message, and the message has not previously
        // been fetched then fire an AJAX request to load the message into the DOM.
        if (! $message.hasClass('sp-message-text-loading') && ! $text.children('.sp-message-text-original').hasClass('sp-message-text-loaded')) {
            $message.find('.sp-message-text').append(
                '<span class="sp-loading sp-description">'
                + '<i class="fa-solid fa-spinner fa-pulse"></i>&nbsp; ' + Lang.get('general.loading') + '...'
                + '</span>'
            );
            $message.addClass('sp-message-text-loading');

            // @ts-ignore
            this.messageDfdNext = this.messageDfdNext.then(() => {
                return $.get(instance.getLoadMessageRoute($message))
                    .done(function (ajax) {
                        // Load the message in, it should already be sanitized.
                        $text.children('.sp-message-text-original')
                            .html(ajax.data.purified_text)
                            .addClass('sp-message-text-loaded');

                        instance.initMessage($message);

                        // If a callback exists, run it.
                        typeof successCallback === 'function' && successCallback();
                    })
                    .fail(function () {
                        Swal.fire(Lang.get('messages.error'), Lang.get('messages.error_loading_message'), 'error');
                    })
                    .always(function () {
                        // Unset loading icon.
                        $message.removeClass('sp-message-text-loading');
                        $message.find('.sp-message-text .sp-loading').remove();
                    })
            });

            return this.messageDfdNext;
        } else {
            // Message has already been loaded.
            this.initMessage($message);

            // Run success callback if exists.
            typeof successCallback === 'function' && successCallback();

            return this.messageDfdNext;
        }
    }

    initMessage($message: JQuery<HTMLElement>): void {
        this.removeExpandableWithoutTextBefore($message);
        this.loadAttachmentPreviews($message);
        this.showDownloadAllButton($message);

        timeAgo.render($message.find('time.timeago'));
    }

    markAsNew($message: JQuery<HTMLElement>): void {
        $message.addClass('sp-new-message');
        setTimeout(function () {
            $message.removeClass('sp-new-message');
        }, 10000);
    }

    showMessage($message: JQuery<HTMLElement>): void {
        // Make the message visible.
        $message.removeClass('sp-message-collapsed').addClass('sp-message-collapsible');
        $message.find('.sp-message-text').children('.sp-message-text-trimmed').addClass('sp:hidden');
        $message.find('.sp-message-text').children('.sp-message-text-original').removeClass('sp:hidden');

        this.initMessage($message);
    }

    loadAttachmentPreviews($message: JQuery<HTMLElement>): void {
        App.attachments.loadPreviews($message);

        $message.find('.sp-attachment-name').each((i, el) => {
            const fullName = $(el).data('filename'), maxLength = 40;
            if (! fullName || fullName.length <= maxLength) return;

            const truncated = truncateMiddle(fullName, maxLength);
            $(el).text(truncated);
            $(el).attr('title', fullName);
        });
    }

    removeExpandableWithoutTextBefore($message: JQuery<HTMLElement>): void {
        var $quote = $message.find('.supportpal_quote:first');
        if ($quote.length === 0) {
            return;
        }

        var text = $message.find('.sp-message-text').children('.sp-message-text-original').text();

        // Check if there is any text before the quoted text.
        if (! text.substring(0, text.indexOf($quote.text())).trim().length) {
            $quote.removeClass('supportpal_quote');
            $quote.prev('.expandable').remove();
        }
    };

    showDownloadAllButton($message: JQuery<HTMLElement>): void {
        if (ZipFile.isSupported()) {
            $message.find('ul.sp-attachments').each(function () {
                // Show the download all button only if there is more than 1 attachment.
                if ($(this).find('li[data-filename]').length > 1) {
                    $(this).find('.sp-download-all').show();
                }
            });
        }
    }

    /**
     * Update avatar visibility after messages are inserted.
     * Default implementation does nothing - can be overridden by subclasses.
     */
    updateAvatarVisibility($container: JQuery<HTMLElement>): void {
        // No-op by default
    }
}
